import React from 'react';
import './App.css';
import GatewayBuilder from './components/GatewayBuilder';

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1>🏭 Industrial Gateway Builder</h1>
        <p>Generate executable industrial protocol gateways</p>
      </header>
      <main className="App-main">
        <GatewayBuilder />
      </main>
    </div>
  );
}

export default App;
